const a={whatsapp:"6285925942277",whatsappDisplay:"+62 859-2594-2277"},n={activeViewers:8},e=[{name:"Ir. H. Dedy Kusnadi",location:"Jakarta",role:"Investor Properti",text:"Awalnya saya ragu beli properti jauh di pinggiran. Tapi setelah melihat konsep Sahid Menantu Resort yang dikelola langsung oleh Sahid Hospitality secara profesional dengan skema bagi hasil transparan, kecemasan saya hilang. Ini adalah warisan produktif yang nyata untuk pensiun saya.",rating:5},{name:"dr. Farah Medina, Sp.A",location:"Bandung",role:"Dokter & Investor",text:"Sangat cocok untuk tempat istirahat keluarga sekaligus investasi pasif. Udara Cicalengka, Bandung Timur masih sangat bersih dan sejuk. Managed by Sahid memastikan villa saya selalu bersih, terawat, dan terhindar dari pusing mencari penyewa sendiri.",rating:5},{name:"Alexander Hartanto",location:"Surabaya",role:"Pengusaha",text:"View 360° perbukitan Bandung-nya menakjubkan sekali. Saya mendapatkan brosur promonya secara lengkap via email, penawaran diskon 200 juta langsung saya amankan. Legalitas SHM juga aman, transaksi sangat transparan sampai selesai.",rating:5},{name:"Hendra Wisnu",location:"Bandung",role:"Pengusaha",text:"Awalnya ragu beli villa di pinggiran. Tapi setelah melihat langsung kawasan dan manajemen Sahid, semua kekhawatiran hilang. Sekarang tinggal terima laporan bagi hasil tiap bulan.",rating:5},{name:"Budi Hartono",location:"Jakarta",role:"Karyawan Swasta",text:"Cicilan Rp 9 juta per bulan, passive income Rp 12 juta. Baru 6 bulan sudah jelas cashflow positif. Worth it banget buat yang cari passive income.",rating:5},{name:"Siti Rahma",location:"Semarang",role:"Dokter",text:"Lokasi Cicalengka benar-benar berbeda — sejuk, hijau, jauh dari hiruk-pikuk. Keluarga betah, tapi villa tetap produktif. Best of both worlds.",rating:5}],i={title:"Promo Spesial Pembelian Bulan Ini",subtitle:"Amankan unit terbaik + bonus eksklusif minggu ini",discount:"Rp 200 Juta",discountDesc:"Potongan harga langsung untuk Master Suite & Deluxe",bonus:"Mobil Listrik Baru",bonusDesc:"Bonus langsung untuk 10 pendaftar pertama",deadline:"2026-07-30T23:59:59+07:00",deadlineLabel:"30 Juli 2026, 23:59 WIB",quota:"10 pendaftar pertama",sk:"Berlaku untuk unit Master Suite & Deluxe. Tidak dapat digabung dengan promo lain. S&K berlaku."},t={contact:a,stats:n,testimonials:e,promo:i};export{t as s};
